#!/usr/bin/env python# -*- coding:utf-8 -*-# @Time : 2025/2/17# @Author : cyq# @File : db_config# @Software: PyCharm# @Desc:from sqlalchemy import Column, String, Integer, INTEGER, ForeignKey, TEXT, JSONfrom app.model import BaseModelclass DBConfig(BaseModel):    __tablename__ = "db_config"    db_name = Column(String(50), nullable=False, comment="数据库自定义名称")    db_type = Column(Integer, nullable=False, comment="数据库类型")    db_host = Column(String(50), nullable=False, comment="数据库地址")    db_port = Column(Integer, nullable=False, comment="数据库端口")    db_username = Column(String(50), nullable=False, comment="数据库用户名")    db_password = Column(String(50), nullable=False, comment="数据库密码")    db_database = Column(String(50), nullable=False, comment="数据库名称")    project_id = Column(INTEGER,                        ForeignKey('project.id', ondelete='CASCADE'),                        nullable=False, comment="项目所属")    @property    def config(self):        if self.db_type == 1:            return {                "host": self.db_host,                "port": self.db_port,                "user": self.db_username,                "password": self.db_password,                "db": self.db_database,                "autocommit": True            }        elif self.db_type == 2:            return {                "host": self.db_host,                "port": self.db_port,                "service_name": self.db_database,                "username": self.db_username,                "password": self.db_password,            }        else:            _ = dict(                host=self.db_host,                port=self.db_port,                db=self.db_database,                decode_responses=True,                max_connections=100            )            if self.db_password and self.db_username:                _.update(password=self.db_password, username=self.db_username)            return _class DBExecuteModel(BaseModel):    """    执行db    """    __tablename__ = 'db_execute'    sql_text = Column(TEXT, nullable=True, comment="sql_text")    sql_extracts = Column(JSON, nullable=True, comment="变量提取")    db_id = Column(INTEGER, nullable=True, comment="数据库id")    def __repr__(self):        text = self.sql_text        if len(self.sql_text) > 10:            text = self.sql_text[0:10]        return f"DBExecuteModel sql_text = {text} ...  extracts = {self.sql_extracts}"